arguments.command:
sqlite3 database.db "SELECT COUNT(*) FROM fdbk_g1 f JOIN items_g1 i ON f.ref_id=i.ref_id WHERE i.main_cat='All Electronics' AND (CASE WHEN LENGTH(f.ts)=13 THEN f.ts/1000 WHEN LENGTH(f.ts)=15 THEN f.ts/1000000 END) >= 1924992000;
SELECT '---';
SELECT COUNT(*) FROM fdbk_g2 f JOIN items_g2 i ON f.ref_id=i.ref_id WHERE i.main_cat='All Electronics' AND (CASE WHEN LENGTH(f.ts)=10 THEN f.ts WHEN LENGTH(f.ts)=12 THEN f.ts/1000 END) >= 1924992000;
SELECT '---';
SELECT COUNT(*) FROM fdbk_g3 f JOIN items_g3 i ON f.ref_id=i.ref_id WHERE i.main_cat='All Electronics' AND f.ts >= '2031-01-01';"

sqlite3 database.db "SELECT MAX(CASE WHEN LENGTH(f.ts)=13 THEN f.ts/1000 WHEN LENGTH(f.ts)=15 THEN f.ts/1000000 END) FROM fdbk_g1 f JOIN items_g1 i ON f.ref_id=i.ref_id WHERE i.main_cat='All Electronics';
SELECT MAX(CASE WHEN LENGTH(f.ts)=10 THEN f.ts WHEN LENGTH(f.ts)=12 THEN f.ts/1000 END) FROM fdbk_g2 f JOIN items_g2 i ON f.ref_id=i.ref_id WHERE i.main_cat='All Electronics';
SELECT MAX(f.ts) FROM fdbk_g3 f JOIN items_g3 i ON f.ref_id=i.ref_id WHERE i.main_cat='All Electronics';"

sqlite3 database.db "SELECT MAX(CASE WHEN LENGTH(ts)=13 THEN ts/1000 WHEN LENGTH(ts)=15 THEN ts/1000000 END) FROM fdbk_g1;
SELECT MAX(CASE WHEN LENGTH(ts)=10 THEN ts WHEN LENGTH(ts)=12 THEN ts/1000 END) FROM fdbk_g2;
SELECT MAX(ts) FROM fdbk_g3;"
